import React, { useState } from 'react';
import { Select } from '@your-design-system/select';

function FruitSelector() {
  const [selectedFruit, setSelectedFruit] = useState('banana');

  return (
    <div>
      <label htmlFor="fruit-select">Choose a fruit:</label>
      <Select
        id="fruit-select"
        value={selectedFruit}
        onValueChange={setSelectedFruit}
      >
        <Select.Trigger aria-label="Fruit">
          <Select.Value />
        </Select.Trigger>
        <Select.Content>
          <Select.Item value="apple">Apple</Select.Item>
          <Select.Item value="banana">Banana</Select.Item>
          <Select.Item value="orange">Orange</Select.Item>
          <Select.Item value="grape">Grape</Select.Item>
        </Select.Content>
      </Select>
      <p>Selected: {selectedFruit}</p>
    </div>
  );
}

import React from 'react';
import { Select } from '@your-design-system/select';

function ContinentSelector() {
  const handleValueChange = (value) => {
    console.log('Selected continent:', value);
  };

  return (
    <div>
      <label htmlFor="continent-select">Select a continent:</label>
      <Select
        id="continent-select"
        defaultValue="europe"
        onValueChange={handleValueChange}
      >
        <Select.Trigger>
          <Select.Value />
        </Select.Trigger>
        <Select.Content>
          <Select.Item value="asia">Asia</Select.Item>
          <Select.Item value="africa">Africa</Select.Item>
          <Select.Item value="europe">Europe</Select.Item>
          <Select.Item value="north-america">North America</Select.Item>
          <Select.Item value="south-america">South America</Select.Item>
          <Select.Item value="australia">Australia</Select.Item>
        </Select.Content>
      </Select>
    </div>
  );
}

import React, { useState } from 'react';
import { Select } from '@your-design-system/select';

function StatusSelector() {
  const [status, setStatus] = useState('');

  return (
    <div>
      <label htmlFor="status-select">Current Status:</label>
      <Select
        id="status-select"
        value={status}
        onValueChange={setStatus}
      >
        <Select.Trigger>
          <Select.Value placeholder="Set your status" />
        </Select.Trigger>
        <Select.Content>
          <Select.Item value="online">Online</Select.Item>
          <Select.Item value="away" disabled>Away (temporarily unavailable)</Select.Item>
          <Select.Item value="offline">Offline</Select.Item>
        </Select.Content>
      </Select>
      <p>Status: {status || 'Not set'}</p>
    </div>
  );
}

